import{_ as e,o as a,c as t,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Execution Models","description":"","frontmatter":{"title":"Execution Models"},"headers":[],"relativePath":"research/concepts/tool-systems/execution-models.md","filePath":"research/concepts/tool-systems/execution-models.md"}'),o={name:"research/concepts/tool-systems/execution-models.md"};function l(p,s,r,i,c,d){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="execution-models" tabindex="-1">Execution Models <a class="header-anchor" href="#execution-models" aria-label="Permalink to &quot;Execution Models&quot;">​</a></h1><p>How coding agent tools actually run — from synchronous blocking calls to persistent shell sessions and parallel dispatch.</p><p>Every coding agent must decide <em>how</em> to execute the tools the LLM requests. This seemingly simple question — &quot;run this command&quot; — branches into a tree of design decisions that profoundly affect reliability, performance, and capability. The execution model determines whether an agent can run tests while editing files, whether environment variables survive between commands, whether a hung process halts the entire agent loop, and whether the agent can recover from partial failures.</p><hr><h2 id="_1-synchronous-execution" tabindex="-1">1. Synchronous Execution <a class="header-anchor" href="#_1-synchronous-execution" aria-label="Permalink to &quot;1. Synchronous Execution&quot;">​</a></h2><p>The simplest execution model: the agent loop blocks until the tool completes, then feeds the result back to the LLM. Most agents use this as their default or only model.</p><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Agent Loop:</span></span>
<span class="line"><span>  1. LLM generates tool_call(name, args)</span></span>
<span class="line"><span>  2. Agent dispatches to tool handler</span></span>
<span class="line"><span>  3. Tool handler BLOCKS until completion</span></span>
<span class="line"><span>  4. Result returned to agent loop</span></span>
<span class="line"><span>  5. Result appended to conversation</span></span>
<span class="line"><span>  6. Back to step 1</span></span></code></pre></div><p>In OpenCode, tools return a <code>ToolResponse</code> synchronously. The tool executor calls the tool&#39;s <code>Run()</code> method and waits for it to return:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// OpenCode tool execution (simplified)</span></span>
<span class="line"><span style="color:#CBA6F7;">func</span><span style="color:#9399B2;"> (</span><span style="color:#EBA0AC;font-style:italic;">e </span><span style="color:#94E2D5;">*</span><span style="color:#F9E2AF;font-style:italic;">Executor</span><span style="color:#9399B2;">)</span><span style="color:#89B4FA;font-style:italic;"> Execute</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">call</span><span style="color:#F9E2AF;font-style:italic;"> ToolCall</span><span style="color:#9399B2;">)</span><span style="color:#F9E2AF;font-style:italic;"> ToolResponse</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    tool </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> e</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">registry</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Get</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">Name</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">    result</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> err </span><span style="color:#94E2D5;">:=</span><span style="color:#CDD6F4;"> tool</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Run</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">Params</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  // blocks here</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> err </span><span style="color:#94E2D5;">!=</span><span style="color:#F38BA8;"> nil</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#F9E2AF;font-style:italic;"> ToolResponse</span><span style="color:#9399B2;">{</span><span style="color:#CDD6F4;">Error</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> err</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Error</span><span style="color:#9399B2;">()}</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#F9E2AF;font-style:italic;"> ToolResponse</span><span style="color:#9399B2;">{</span><span style="color:#CDD6F4;">Content</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>In mini-SWE-agent, the pattern is even more explicit — <code>subprocess.run</code> is inherently blocking:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># mini-SWE-agent: blocking subprocess execution</span></span>
<span class="line"><span style="color:#CDD6F4;">result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> subprocess</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#CDD6F4;">    command</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    shell</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    capture_output</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    timeout</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">timeout</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">    text</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span></span>
<span class="line"><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">return</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stdout </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stderr</span></span></code></pre></div><h3 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h3><p><strong>Advantages:</strong></p><ul><li>Dead simple to implement and reason about</li><li>Deterministic ordering — tool A always completes before tool B starts</li><li>Easy to debug: stack traces are linear, logs are sequential</li><li>No race conditions, no shared state conflicts</li><li>Error handling is straightforward (try/catch around the call)</li></ul><p><strong>Disadvantages:</strong></p><ul><li>Slow for I/O-heavy workflows (e.g., running tests then reading results)</li><li>A single slow tool blocks the entire agent loop</li><li>Cannot overlap independent operations (edit file A while running tests on file B)</li><li>Timeout handling becomes critical — a hung tool freezes everything</li></ul><p>Most agents start synchronous and add async capabilities only when performance demands it.</p><hr><h2 id="_2-asynchronous-execution" tabindex="-1">2. Asynchronous Execution <a class="header-anchor" href="#_2-asynchronous-execution" aria-label="Permalink to &quot;2. Asynchronous Execution&quot;">​</a></h2><p>Non-blocking tool execution allows the agent to dispatch work and continue processing without waiting for each tool to complete. This is architecturally more complex but enables parallel operations and better throughput.</p><h3 id="goose-async-via-tokio-runtime" tabindex="-1">Goose: Async via Tokio Runtime <a class="header-anchor" href="#goose-async-via-tokio-runtime" aria-label="Permalink to &quot;Goose: Async via Tokio Runtime&quot;">​</a></h3><p>Goose is written in Rust and uses the <code>tokio</code> async runtime for tool dispatch. MCP tool calls are sent asynchronously, and the runtime manages concurrent execution:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Goose: async MCP tool invocation (conceptual)</span></span>
<span class="line"><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> call_tool</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> params</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Value</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Value</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> client </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">mcp_client</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> client</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">call_tool</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">name</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> params</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">response</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">content</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The tokio runtime allows Goose to dispatch multiple MCP calls concurrently when the LLM requests parallel tool use. Each call is a future that resolves independently.</p><h3 id="openhands-event-driven-async" tabindex="-1">OpenHands: Event-Driven Async <a class="header-anchor" href="#openhands-event-driven-async" aria-label="Permalink to &quot;OpenHands: Event-Driven Async&quot;">​</a></h3><p>OpenHands uses an event stream architecture. Actions are dispatched as events, and observations come back asynchronously through the <code>EventStreamRuntime</code>:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># OpenHands: event-driven execution (conceptual)</span></span>
<span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> EventStreamRuntime</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> def</span><span style="color:#89B4FA;font-style:italic;"> execute</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> action</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> Action</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> Observation</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        event_id </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">event_stream</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">publish</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">action</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">        observation </span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;"> await</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">event_stream</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">wait_for</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">event_id</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> observation</span></span></code></pre></div><p>This decouples tool invocation from result handling. The runtime can process multiple actions concurrently, and the agent controller manages result ordering.</p><h3 id="handling-async-results" tabindex="-1">Handling Async Results <a class="header-anchor" href="#handling-async-results" aria-label="Permalink to &quot;Handling Async Results&quot;">​</a></h3><p>Agents use several patterns to handle asynchronous results:</p><ul><li><strong>Futures/Promises</strong>: Goose awaits futures directly. The agent loop suspends at await points and resumes when results arrive.</li><li><strong>Event Streams</strong>: OpenHands publishes actions and subscribes to observations. The event bus handles routing and ordering.</li><li><strong>Callbacks</strong>: Some frameworks register completion callbacks that fire when a tool finishes, appending results to the conversation.</li></ul><p>The key challenge is <em>ordering</em>: when tools complete out of order, the agent must decide how to present results to the LLM. Most agents collect all parallel results and present them together in the order they were requested, not the order they completed.</p><hr><h2 id="_3-persistent-shell-sessions" tabindex="-1">3. Persistent Shell Sessions <a class="header-anchor" href="#_3-persistent-shell-sessions" aria-label="Permalink to &quot;3. Persistent Shell Sessions&quot;">​</a></h2><p>Most production agents keep a bash shell session alive across multiple tool calls. This is one of the most consequential design decisions — it determines whether state accumulates naturally (like a human developer&#39;s terminal) or must be explicitly reconstructed each time.</p><h3 id="why-persistence-matters" tabindex="-1">Why Persistence Matters <a class="header-anchor" href="#why-persistence-matters" aria-label="Permalink to &quot;Why Persistence Matters&quot;">​</a></h3><p>A developer working in a terminal builds up state: they <code>cd</code> into a project, set environment variables, activate virtual environments, define aliases. Persistent shells let agent tools behave the same way:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Call 1: Navigate and setup</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> /workspace/myproject</span><span style="color:#9399B2;"> &amp;&amp;</span><span style="color:#F38BA8;font-style:italic;"> source</span><span style="color:#A6E3A1;"> venv/bin/activate</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Call 2: This works because CWD and venv persist</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">pip</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> -r</span><span style="color:#A6E3A1;"> requirements.txt</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Call 3: Environment is still active</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">python</span><span style="color:#A6E3A1;"> -m</span><span style="color:#A6E3A1;"> pytest</span><span style="color:#A6E3A1;"> tests/</span></span></code></pre></div><p>Without persistence, each of those commands would need the full context repeated.</p><h3 id="implementation-patterns" tabindex="-1">Implementation Patterns <a class="header-anchor" href="#implementation-patterns" aria-label="Permalink to &quot;Implementation Patterns&quot;">​</a></h3><p><strong>OpenCode</strong> creates a persistent shell via <code>GetPersistentShell()</code>. The shell process stays alive between tool invocations, preserving working directory, environment variables, and shell state:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// OpenCode: persistent shell (simplified from shell.go)</span></span>
<span class="line"><span style="color:#CBA6F7;">func</span><span style="color:#89B4FA;font-style:italic;"> GetPersistentShell</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> *</span><span style="color:#F9E2AF;font-style:italic;">Shell</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> persistentShell </span><span style="color:#94E2D5;">==</span><span style="color:#F38BA8;"> nil</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        persistentShell </span><span style="color:#94E2D5;">=</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">Shell</span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">            cmd</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> exec</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Command</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;bash&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;--norc&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;--noprofile&quot;</span><span style="color:#9399B2;">),</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#CDD6F4;">        persistentShell</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">cmd</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Start</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> persistentShell</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Commands are written to the shell&#39;s stdin, and output is read from stdout/stderr. Sentinel markers delimit where one command&#39;s output ends and the next begins.</p><p><strong>Gemini CLI</strong> similarly maintains a persistent shell session. Commands execute within the same process, so <code>export FOO=bar</code> in one call makes <code>$FOO</code> available in the next.</p><p><strong>OpenHands</strong> runs a persistent shell <em>inside a Docker container</em>. The shell persists for the entire agent session, and because it&#39;s containerized, the accumulated state is isolated from the host system.</p><h3 id="pty-pseudo-terminal-management" tabindex="-1">PTY (Pseudo-Terminal) Management <a class="header-anchor" href="#pty-pseudo-terminal-management" aria-label="Permalink to &quot;PTY (Pseudo-Terminal) Management&quot;">​</a></h3><p>Some agents use PTY allocation for their persistent shells. A PTY provides proper terminal emulation, which matters for:</p><ul><li><strong>Interactive programs</strong>: Tools like <code>git log</code>, <code>less</code>, or <code>top</code> behave differently without a TTY. Many programs disable color output or change formatting when they detect no terminal.</li><li><strong>Line discipline</strong>: PTYs handle line editing, signal delivery (Ctrl+C), and terminal resizing — important for programs that use ncurses or similar libraries.</li><li><strong>Output capture</strong>: PTY-based output includes ANSI escape codes for colors and formatting. Agents must decide whether to strip these or pass them through.</li></ul><p>Warp terminal pioneered a <em>block-based</em> PTY model where each command&#39;s input and output is treated as a discrete block. This concept influenced how some agents structure their tool output — each command invocation produces a self-contained block of output rather than a continuous stream.</p><p>Agents that capture PTY output typically:</p><ol><li>Allocate a PTY pair (master/slave)</li><li>Run the shell connected to the slave end</li><li>Read from the master end to capture output</li><li>Strip ANSI escape codes before sending to the LLM (most models cannot use them)</li><li>Preserve raw output for display to the user</li></ol><h3 id="state-accumulation" tabindex="-1">State Accumulation <a class="header-anchor" href="#state-accumulation" aria-label="Permalink to &quot;State Accumulation&quot;">​</a></h3><p>Persistent shells accumulate state in ways that can be both powerful and dangerous:</p><p><strong>Useful accumulation:</strong></p><ul><li>Working directory changes (<code>cd</code> persists)</li><li>Environment variables (<code>export PATH=$PATH:/new/dir</code>)</li><li>Shell functions and aliases</li><li>Virtual environment activation</li><li>SSH agent forwarding</li></ul><p><strong>Dangerous accumulation:</strong></p><ul><li>Background processes left running</li><li>Modified shell options (<code>set -e</code>, <code>shopt</code> changes)</li><li>Overridden PATH entries hiding expected binaries</li><li>Resource leaks (open file descriptors, temp files)</li></ul><h3 id="comparison-table" tabindex="-1">Comparison Table <a class="header-anchor" href="#comparison-table" aria-label="Permalink to &quot;Comparison Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Shell Persistence</th><th>Env Vars Persist?</th><th>CWD Persists?</th><th>Isolation</th></tr></thead><tbody><tr><td>OpenCode</td><td>Persistent process</td><td>Yes</td><td>Yes</td><td>Host process</td></tr><tr><td>Claude Code</td><td>Separate per command</td><td>No</td><td>Yes (tracked)</td><td>Process-level</td></tr><tr><td>Codex</td><td>Sandboxed per command</td><td>Per-sandbox</td><td>Per-sandbox</td><td>Network-disabled sandbox</td></tr><tr><td>Gemini CLI</td><td>Persistent process</td><td>Yes</td><td>Yes</td><td>Host process</td></tr><tr><td>OpenHands</td><td>Persistent in Docker</td><td>Yes</td><td>Yes</td><td>Container-level</td></tr><tr><td>mini-SWE-agent</td><td>New subprocess each</td><td>No</td><td>No</td><td>Process-level</td></tr><tr><td>Goose</td><td>Persistent shell</td><td>Yes</td><td>Yes</td><td>Host process</td></tr></tbody></table><p>Claude Code is notable for tracking CWD <em>without</em> a persistent shell — it maintains the current directory in agent state and prepends <code>cd /tracked/dir &amp;&amp;</code> to each command. This gives the <em>illusion</em> of persistence for directory navigation while maintaining process isolation.</p><hr><h2 id="_4-stateless-subprocess-model" tabindex="-1">4. Stateless Subprocess Model <a class="header-anchor" href="#_4-stateless-subprocess-model" aria-label="Permalink to &quot;4. Stateless Subprocess Model&quot;">​</a></h2><p>The opposite extreme from persistent shells: every tool invocation spawns a fresh subprocess. mini-SWE-agent is the canonical example of this approach.</p><h3 id="how-mini-swe-agent-does-it" tabindex="-1">How mini-SWE-agent Does It <a class="header-anchor" href="#how-mini-swe-agent-does-it" aria-label="Permalink to &quot;How mini-SWE-agent Does It&quot;">​</a></h3><p>Each action creates a brand-new subprocess with no memory of previous commands:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># mini-SWE-agent: stateless subprocess execution</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> execute_command</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">command</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> timeout</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> subprocess</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#CDD6F4;">        command</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        shell</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        capture_output</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        timeout</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">timeout</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        text</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">        cwd</span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">working_dir  </span><span style="color:#6C7086;font-style:italic;"># explicitly set each time</span></span>
<span class="line"><span style="color:#9399B2;">    )</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stdout </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> result</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stderr</span></span></code></pre></div><p>Because nothing persists, the system prompt teaches the model to chain commands:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span># This WON&#39;T work (cd is lost between calls):</span></span>
<span class="line"><span># Call 1: cd /workspace/project</span></span>
<span class="line"><span># Call 2: ls src/  &lt;-- runs in wrong directory</span></span>
<span class="line"><span></span></span>
<span class="line"><span># This WILL work (single command chain):</span></span>
<span class="line"><span>cd /workspace/project &amp;&amp; ls src/</span></span></code></pre></div><h3 id="environment-configuration" tabindex="-1">Environment Configuration <a class="header-anchor" href="#environment-configuration" aria-label="Permalink to &quot;Environment Configuration&quot;">​</a></h3><p>Since environment variables do not persist between calls, mini-SWE-agent configures them once via YAML in the action space definition:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># mini-SWE-agent: environment configuration</span></span>
<span class="line"><span style="color:#89B4FA;">env_variables</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  PAGER</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;cat&quot;</span><span style="color:#6C7086;font-style:italic;">               # Prevent interactive pagers</span></span>
<span class="line"><span style="color:#89B4FA;">  PIP_PROGRESS_BAR</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;off&quot;</span><span style="color:#6C7086;font-style:italic;">    # Disable progress bars</span></span>
<span class="line"><span style="color:#89B4FA;">  GIT_TERMINAL_PROMPT</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;0&quot;</span><span style="color:#6C7086;font-style:italic;">   # Prevent git auth prompts</span></span>
<span class="line"><span style="color:#89B4FA;">  PYTHONDONTWRITEBYTECODE</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;1&quot;</span></span></code></pre></div><p>These are injected into every subprocess&#39;s environment, ensuring consistent behavior without relying on shell state.</p><h3 id="trade-offs-stateless-vs-persistent" tabindex="-1">Trade-offs: Stateless vs Persistent <a class="header-anchor" href="#trade-offs-stateless-vs-persistent" aria-label="Permalink to &quot;Trade-offs: Stateless vs Persistent&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Dimension</th><th>Stateless Subprocess</th><th>Persistent Shell</th></tr></thead><tbody><tr><td><strong>Isolation</strong></td><td>Natural — each command is fresh</td><td>Must be managed (cleanup, reset)</td></tr><tr><td><strong>Simplicity</strong></td><td>No shell state management needed</td><td>Complex lifecycle management</td></tr><tr><td><strong>Performance</strong></td><td>Process creation overhead per call</td><td>One-time setup, fast subsequent calls</td></tr><tr><td><strong>Debugging</strong></td><td>No session history to inspect</td><td>Rich history within session</td></tr><tr><td><strong>Reproducibility</strong></td><td>High — same input, same output</td><td>State-dependent (order matters)</td></tr><tr><td><strong>State management</strong></td><td>Explicit (pass everything each time)</td><td>Implicit (state accumulates)</td></tr><tr><td><strong>Error recovery</strong></td><td>Trivial — just spawn a new process</td><td>May need to reset corrupted state</td></tr><tr><td><strong>Multi-step workflows</strong></td><td>Verbose (repeat context each time)</td><td>Natural (state carries forward)</td></tr></tbody></table><p>The stateless model trades convenience for reliability. In production SWE-bench evaluations, mini-SWE-agent&#39;s stateless approach performs well because each command is self-contained — there is no risk of accumulated state causing subtle bugs across a long agent trajectory.</p><p>The persistent model trades reliability for ergonomics. It is closer to how humans work and requires fewer tokens (no repeated <code>cd</code> and <code>export</code> commands), but introduces a class of bugs that only manifest after many tool calls.</p><hr><h2 id="_5-parallel-tool-execution" tabindex="-1">5. Parallel Tool Execution <a class="header-anchor" href="#_5-parallel-tool-execution" aria-label="Permalink to &quot;5. Parallel Tool Execution&quot;">​</a></h2><p>When an LLM returns multiple tool calls in a single response, should the agent execute them sequentially or in parallel? This decision affects both performance and correctness.</p><h3 id="agent-support-matrix" tabindex="-1">Agent Support Matrix <a class="header-anchor" href="#agent-support-matrix" aria-label="Permalink to &quot;Agent Support Matrix&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Parallel?</th><th>Mechanism</th><th>Notes</th></tr></thead><tbody><tr><td>OpenHands</td><td>Yes</td><td>Multiple tool_calls processed together</td><td>Event stream handles concurrency</td></tr><tr><td>Claude Code</td><td>Yes</td><td>Multiple tool_use blocks</td><td>Read operations parallelized</td></tr><tr><td>Codex</td><td>Yes</td><td>Multiple FunctionCall items</td><td>Sandbox isolation enables safety</td></tr><tr><td>Goose</td><td>Yes</td><td>Async dispatch via tokio</td><td>MCP calls run concurrently</td></tr><tr><td>Gemini CLI</td><td>Yes</td><td>Multiple tool calls supported</td><td>Implementation-dependent</td></tr><tr><td>OpenCode</td><td>No</td><td>Sequential, one at a time</td><td>Simpler but slower</td></tr><tr><td>mini-SWE-agent</td><td>No</td><td>Single command per step</td><td>By design — one action per turn</td></tr><tr><td>Aider</td><td>N/A</td><td>No function calling</td><td>Uses edit blocks in text</td></tr></tbody></table><h3 id="benefits-of-parallel-execution" tabindex="-1">Benefits of Parallel Execution <a class="header-anchor" href="#benefits-of-parallel-execution" aria-label="Permalink to &quot;Benefits of Parallel Execution&quot;">​</a></h3><ol><li><strong>Throughput</strong>: Reading 5 files in parallel takes ~1x the time instead of ~5x</li><li><strong>Latency hiding</strong>: Slow I/O operations overlap with fast computations</li><li><strong>Better LLM utilization</strong>: The model can request all information it needs at once</li><li><strong>Natural batching</strong>: &quot;Read these 3 files and run the tests&quot; executes optimally</li></ol><h3 id="challenges" tabindex="-1">Challenges <a class="header-anchor" href="#challenges" aria-label="Permalink to &quot;Challenges&quot;">​</a></h3><p><strong>Resource contention</strong>: Two parallel file edits to the same file create a race condition. Agents must detect conflicting operations and serialize them:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Pseudocode: conflict detection for parallel tool calls</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> can_parallelize</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">calls</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> list</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> list</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Group tool calls into parallelizable batches.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    batches </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> []</span></span>
<span class="line"><span style="color:#CDD6F4;">    current_batch </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> []</span></span>
<span class="line"><span style="color:#CDD6F4;">    written_files </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;font-style:italic;"> set</span><span style="color:#9399B2;">()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> call </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> calls</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        target </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> call</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">get_target_file</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> target </span><span style="color:#CBA6F7;">and</span><span style="color:#CDD6F4;"> target </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> written_files</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            # Conflict -- start new batch</span></span>
<span class="line"><span style="color:#CDD6F4;">            batches</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">append</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">current_batch</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">            current_batch </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">            written_files </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;">target</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#CBA6F7;">        else</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">            current_batch</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">append</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">            if</span><span style="color:#CDD6F4;"> target</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">                written_files</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">add</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">target</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> current_batch</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        batches</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">append</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">current_batch</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> batches</span></span></code></pre></div><p><strong>Ordering dependencies</strong>: &quot;Create the file, then run the tests&quot; must be sequential. The agent (or the LLM) must understand causal dependencies between operations.</p><p><strong>Error handling</strong>: If 3 of 5 parallel operations succeed and 2 fail, should the agent:</p><ul><li>Report all results (including partial successes)?</li><li>Roll back the successes?</li><li>Retry only the failures?</li></ul><p>Most agents report all results and let the LLM decide how to handle partial failures.</p><p><strong>Determinism</strong>: Parallel execution introduces non-determinism in completion order. Agents typically restore the <em>request order</em> when presenting results to the LLM, regardless of which tool finished first.</p><h3 id="how-agents-determine-parallelizability" tabindex="-1">How Agents Determine Parallelizability <a class="header-anchor" href="#how-agents-determine-parallelizability" aria-label="Permalink to &quot;How Agents Determine Parallelizability&quot;">​</a></h3><p>Most agents delegate this decision to the LLM. When the model returns multiple <code>tool_use</code> blocks in a single response, the agent treats them as parallelizable. The model is expected to understand that &quot;read file A&quot; and &quot;read file B&quot; are independent, while &quot;write file A&quot; and &quot;read file A&quot; are not.</p><p>Some agents add guardrails:</p><ul><li><strong>Read-only operations</strong> are always safe to parallelize</li><li><strong>Write operations</strong> to different files can run in parallel</li><li><strong>Write operations</strong> to the same file are serialized</li><li><strong>Shell commands</strong> may or may not be safe depending on side effects</li></ul><hr><h2 id="_6-timeout-management" tabindex="-1">6. Timeout Management <a class="header-anchor" href="#_6-timeout-management" aria-label="Permalink to &quot;6. Timeout Management&quot;">​</a></h2><p>Timeouts are critical safety mechanisms. Without them, an LLM-generated infinite loop or a network request to a dead server would hang the agent indefinitely.</p><h3 id="timeout-configuration-across-agents" tabindex="-1">Timeout Configuration Across Agents <a class="header-anchor" href="#timeout-configuration-across-agents" aria-label="Permalink to &quot;Timeout Configuration Across Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Default Timeout</th><th>Max Timeout</th><th>Termination Behavior</th></tr></thead><tbody><tr><td>OpenCode</td><td>60s</td><td>10min</td><td>Force stop process</td></tr><tr><td>OpenHands</td><td>Configurable</td><td>Per parameter</td><td>Force terminate container cmd</td></tr><tr><td>Codex</td><td>Configurable</td><td>Per policy</td><td>Terminate + report to LLM</td></tr><tr><td>mini-SWE-agent</td><td>Configurable</td><td>Per YAML config</td><td>subprocess.run raises TimeoutExpired</td></tr><tr><td>Ante</td><td>30s</td><td>Configurable</td><td>Returns ToolError::Timeout</td></tr><tr><td>ForgeCode</td><td>300s</td><td>FORGE_TOOL_TIMEOUT env</td><td>Terminate hung commands</td></tr><tr><td>Goose</td><td>Per-extension</td><td>300s default</td><td>MCP protocol timeout</td></tr></tbody></table><h3 id="why-timeouts-matter" tabindex="-1">Why Timeouts Matter <a class="header-anchor" href="#why-timeouts-matter" aria-label="Permalink to &quot;Why Timeouts Matter&quot;">​</a></h3><p>LLMs can and do generate commands that run forever:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># LLM might generate this trying to &quot;watch&quot; for changes</span></span>
<span class="line"><span style="color:#CBA6F7;">while</span><span style="color:#CBA6F7;"> True</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    check_status</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CDD6F4;">    time</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">sleep</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">1</span><span style="color:#9399B2;">)</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Or a network request to an unreachable host</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> https://internal-service.company.com/api</span><span style="color:#6C7086;font-style:italic;">  # hangs for minutes</span></span></code></pre></div><p>Without timeouts, any of these would freeze the agent. The timeout is the last line of defense against runaway execution.</p><h3 id="graceful-vs-hard-termination" tabindex="-1">Graceful vs Hard Termination <a class="header-anchor" href="#graceful-vs-hard-termination" aria-label="Permalink to &quot;Graceful vs Hard Termination&quot;">​</a></h3><p><strong>Graceful shutdown</strong> (SIGTERM, then wait, then force stop):</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Two-phase termination pattern</span></span>
<span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> signal</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> terminate_gracefully</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">process</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> timeout</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">5</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">    process</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">send_signal</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">signal</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">SIGTERM</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">    # ask nicely first</span></span>
<span class="line"><span style="color:#CBA6F7;">    try</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        process</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">wait</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">timeout</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">timeout</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">      # give it time to clean up</span></span>
<span class="line"><span style="color:#CBA6F7;">    except</span><span style="color:#CDD6F4;"> subprocess</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">TimeoutExpired</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        process</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">send_signal</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">signal</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">SIGKILL</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # force if unresponsive</span></span></code></pre></div><p>This gives the process a chance to clean up (flush buffers, remove temp files, release locks) before forcibly terminating it. Most production agents use this pattern.</p><p><strong>Hard termination</strong> (immediate forced stop): Simpler but risks:</p><ul><li>Corrupted files (partial writes)</li><li>Leaked resources (temp files, network sockets)</li><li>Zombie child processes</li></ul><h3 id="cascading-timeouts" tabindex="-1">Cascading Timeouts <a class="header-anchor" href="#cascading-timeouts" aria-label="Permalink to &quot;Cascading Timeouts&quot;">​</a></h3><p>Production agents often implement multiple timeout layers:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Per-command timeout:  60s  (individual tool call)</span></span>
<span class="line"><span>Per-step timeout:    300s  (entire agent step including LLM call)</span></span>
<span class="line"><span>Per-task timeout:   3600s  (entire task/conversation)</span></span></code></pre></div><p>If a per-command timeout fires, only that command is stopped. If a per-step timeout fires, the entire step is abandoned. If a per-task timeout fires, the agent shuts down gracefully.</p><hr><h2 id="_7-resource-limits" tabindex="-1">7. Resource Limits <a class="header-anchor" href="#_7-resource-limits" aria-label="Permalink to &quot;7. Resource Limits&quot;">​</a></h2><p>Beyond timeouts, agents need to constrain CPU, memory, disk, and network usage to prevent runaway processes from destabilizing the host system.</p><h3 id="cpu-limits" tabindex="-1">CPU Limits <a class="header-anchor" href="#cpu-limits" aria-label="Permalink to &quot;CPU Limits&quot;">​</a></h3><p>Docker-based agents (OpenHands, Codex in container mode) use cgroups to limit CPU:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Docker CPU limits</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">docker</span><span style="color:#A6E3A1;"> run</span><span style="color:#A6E3A1;"> --cpus=&quot;2.0&quot;</span><span style="color:#A6E3A1;"> --cpu-shares=1024</span><span style="color:#A6E3A1;"> agent-sandbox</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Equivalent cgroup configuration</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#FAB387;"> 200000</span><span style="color:#94E2D5;"> &gt;</span><span style="color:#A6E3A1;"> /sys/fs/cgroup/cpu/agent/cpu.cfs_quota_us</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#FAB387;"> 100000</span><span style="color:#94E2D5;"> &gt;</span><span style="color:#A6E3A1;"> /sys/fs/cgroup/cpu/agent/cpu.cfs_period_us</span></span></code></pre></div><p>This prevents a CPU-intensive build from starving other processes on the host.</p><h3 id="memory-limits" tabindex="-1">Memory Limits <a class="header-anchor" href="#memory-limits" aria-label="Permalink to &quot;Memory Limits&quot;">​</a></h3><p>Memory limits prevent OOM (Out of Memory) conditions from crashing the host:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Docker memory limits</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">docker</span><span style="color:#A6E3A1;"> run</span><span style="color:#A6E3A1;"> --memory=&quot;4g&quot;</span><span style="color:#A6E3A1;"> --memory-swap=&quot;4g&quot;</span><span style="color:#A6E3A1;"> agent-sandbox</span></span></code></pre></div><p>When a process exceeds its memory limit, the OOM handler terminates it. Agents must handle this gracefully — detecting OOM events and reporting them to the LLM as actionable errors rather than opaque crashes.</p><h3 id="disk-limits" tabindex="-1">Disk Limits <a class="header-anchor" href="#disk-limits" aria-label="Permalink to &quot;Disk Limits&quot;">​</a></h3><p>Agents constrain disk usage through:</p><ul><li><strong>tmpfs mounts</strong>: In-memory filesystems with size limits for temp directories</li><li><strong>Quota enforcement</strong>: Filesystem quotas on the workspace directory</li><li><strong>Cleanup policies</strong>: Periodic removal of build artifacts and cache files</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># tmpfs with size limit for temp directory</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">docker</span><span style="color:#A6E3A1;"> run</span><span style="color:#A6E3A1;"> --tmpfs</span><span style="color:#A6E3A1;"> /tmp:size=512m</span><span style="color:#A6E3A1;"> agent-sandbox</span></span></code></pre></div><h3 id="network-limits" tabindex="-1">Network Limits <a class="header-anchor" href="#network-limits" aria-label="Permalink to &quot;Network Limits&quot;">​</a></h3><p>Network restrictions are perhaps the most important resource limit for security:</p><table tabindex="0"><thead><tr><th>Approach</th><th>Used By</th><th>Restrictions</th></tr></thead><tbody><tr><td>No network</td><td>Codex (default)</td><td>All outbound blocked</td></tr><tr><td>Allowlist</td><td>Codex (--full-auto)</td><td>Only approved domains</td></tr><tr><td>Docker network</td><td>OpenHands</td><td>Configurable per container</td></tr><tr><td>Host network</td><td>OpenCode, Gemini CLI</td><td>No restrictions (host trust)</td></tr></tbody></table><p>Codex&#39;s default of <em>no network access</em> is the most restrictive. This prevents data exfiltration, dependency confusion attacks, and accidental API calls. The trade-off is that the agent cannot install packages or access external services during execution.</p><h3 id="compound-resource-policies" tabindex="-1">Compound Resource Policies <a class="header-anchor" href="#compound-resource-policies" aria-label="Permalink to &quot;Compound Resource Policies&quot;">​</a></h3><p>Production deployments typically combine multiple limits:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Example: composite resource policy</span></span>
<span class="line"><span style="color:#89B4FA;">resources</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  cpu</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    cores</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 2</span></span>
<span class="line"><span style="color:#89B4FA;">    throttle_at</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> 90%</span></span>
<span class="line"><span style="color:#89B4FA;">  memory</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    limit</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> 4GB</span></span>
<span class="line"><span style="color:#89B4FA;">    swap</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 0</span><span style="color:#6C7086;font-style:italic;">          # No swap -- fail fast on OOM</span></span>
<span class="line"><span style="color:#89B4FA;">  disk</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    workspace</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> 10GB</span></span>
<span class="line"><span style="color:#89B4FA;">    temp</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> 512MB</span></span>
<span class="line"><span style="color:#89B4FA;">  network</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    mode</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> allowlist</span></span>
<span class="line"><span style="color:#89B4FA;">    allowed</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#A6E3A1;"> &quot;*.npmjs.org&quot;</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#A6E3A1;"> &quot;*.pypi.org&quot;</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#A6E3A1;"> &quot;github.com&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">  timeout</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    per_command</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> 120s</span></span>
<span class="line"><span style="color:#89B4FA;">    per_session</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> 3600s</span></span></code></pre></div><p>The interaction between these limits matters. A memory-constrained process might swap to disk, consuming disk I/O. A CPU-limited build might take longer, hitting timeouts. Good resource policies consider these interactions and set limits that work together rather than creating cascading failures.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The execution model is a foundational architectural decision that ripples through every aspect of an agent&#39;s behavior:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th><th>Watch Out For</th></tr></thead><tbody><tr><td>Synchronous</td><td>Simple agents, debugging</td><td>Blocking on slow operations</td></tr><tr><td>Asynchronous</td><td>High-throughput, parallel I/O</td><td>Complexity, ordering bugs</td></tr><tr><td>Persistent Shell</td><td>Natural developer workflows</td><td>State accumulation bugs</td></tr><tr><td>Stateless Subprocess</td><td>Reproducibility, isolation</td><td>Verbosity, repeated setup</td></tr><tr><td>Parallel Dispatch</td><td>Multi-file operations</td><td>Race conditions, conflicts</td></tr></tbody></table><p>The trend in production agents is toward <strong>persistent shells with async dispatch and comprehensive resource limits</strong> — combining the ergonomics of a real terminal with the safety guarantees needed for autonomous operation.</p>`,144)])])}const h=e(o,[["render",l]]);export{u as __pageData,h as default};
